SELECT DISTINCT u.`USER_ID`,u.`USERNAME`,u.`REAL_NAME`,u.LAST_UPDATED_DATE,GET_ORG_NAME(u.org_id) as ORG_NAME
  FROM sys_user u WHERE u.USER_ID > -1 AND u.DELETED = 0

    AND NOT EXISTS (SELECT a.user_id FROM sys_user a WHERE u.USER_ID = a.USER_ID AND a.USER_ID IN (${excepted}))


    and  u.USERNAMElike '%${username}%'




            AND u.ORG_ID IN (
            SELECT ORG_ID FROM sys_org WHERE FIND_IN_SET(org_id, Get_OrgChild_List(#{orgId,jdbcType=NUMERIC}))
            )


            and u.org_id =${orgId}




    order by ${sort} ${order}

ORDER BY u.LAST_UPDATED_DATE DESC

